from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase. Handles multiple subjects and creates relationships between entities.
    """
    if not triples:
        return ""

    # Clean object values (remove surrounding quotes)
    for triple in triples:
        triple.object = triple.object.strip('"')

    # Group triples by subject
    from collections import defaultdict
    subject_triples = defaultdict(list)
    for triple in triples:
        subject_triples[triple.subject].append(triple)

    # Find the main subject (most triples or first one)
    main_subject = max(subject_triples.keys(), key=lambda s: len(subject_triples[s]))
    other_subjects = [s for s in subject_triples.keys() if s != main_subject]

    clauses: list[str] = []
    location_info = []
    country_info = []
    related_entities = []

    # Process main subject triples
    for triple in subject_triples[main_subject]:
        p = triple.predicate
        o = triple.object

        if p == "category":
            clauses.append(f"is a {o}")
        elif p == "country":
            country_info.append(o)
        elif p == "location":
            location_info.append(o)
        elif p == "municipality":
            clauses.append(f"located in the municipality of {o}")
        elif p == "state":
            clauses.append(f"in the state of {o}")
        elif p == "district":
            clauses.append(f"part of the district {o}")
        elif p in ("established", "foundingDate"):
            clauses.append(f"was established on {o}")
        elif p in ("owner", "owningOrganisation"):
            clauses.append(f"is owned by {o}")
        elif p == "inaugurationDate":
            clauses.append(f"was inaugurated on {o}")
        elif p == "capital":
            related_entities.append(f"the capital is {o}")
        elif p == "legislature":
            related_entities.append(f"the legislature is {o}")
        elif p == "dedicatedTo":
            clauses.append(f"is dedicated to {o}")
        elif p == "designer":
            clauses.append(f"was designed by {o}")
        elif p == "material":
            clauses.append(f"is made of {o}")
        elif p == "ethnicGroup":
            related_entities.append(f"ethnic group {o}")
        elif p == "language":
            related_entities.append(f"language {o}")
        elif p == "religion":
            related_entities.append(f"religion {o}")
        elif p == "nearestCity":
            clauses.append(f"nearest city is {o}")
        elif p == "currency":
            related_entities.append(f"currency {o}")
        elif p == "largestCity":
            related_entities.append(f"largest city is {o}")
        elif p == "leader":
            related_entities.append(f"leader {o}")
        elif p == "leaderTitle":
            related_entities.append(f"leader title {o}")
        elif p.startswith("hasToIts"):
            direction = p.replace("hasToIts", "").lower()
            related_entities.append(f"to its {direction} is {o}")
        elif p == "nativeName":
            clauses.append(f'native name is "{o}"')
        else:
            clauses.append(f"{p.replace('_', ' ')} {o}")

    # Build location phrase
    location_phrase = ""
    if location_info:
        location_phrase = f" located in {', '.join(location_info)}"
        if country_info:
            location_phrase += f" in {', '.join(country_info)}"
    elif country_info:
        location_phrase = f" located in {', '.join(country_info)}"

    # Build main clause
    if clauses:
        main_clause = f"{main_subject}{location_phrase}, " + ", ".join(clauses)
    else:
        main_clause = f"{main_subject}{location_phrase}"

    # Add related entity information
    if related_entities:
        main_clause += f", where {', '.join(related_entities)}"

    # Handle other subjects (create relationships)
    for other_subj in other_subjects:
        for triple in subject_triples[other_subj]:
            p = triple.predicate
            o = triple.object
            if p == "capital" and main_subject in o:
                main_clause += f", where {other_subj} is the capital"
            elif p == "country" and main_subject == o:
                main_clause += f", which is in {other_subj}"
            elif p == "cityServed":
                main_clause += f", serving {other_subj}"

    return main_clause + "."

